def perceive(data):
    out = {}
    if isinstance(data, dict):
        if "price" in data:
            try:
                out["price"] = float(data["price"])
            except (ValueError, TypeError):
                pass
        return out
    text = str(data)
    for line in text.replace(",", "\n").split("\n"):
        if ":" in line:
            key, _, val = line.partition(":")
            if key.strip().lower() == "price":
                try:
                    out["price"] = float(val.strip())
                except (ValueError, TypeError):
                    pass
    return out
